SET ANSI_NULLS ON;
GO
SET QUOTED_IDENTIFIER ON;
GO

CREATE OR ALTER PROCEDURE dbo.usp_get_broadcast_result_listings(
    @contest_year INT,
    @contest_stage NVARCHAR(10)
)
AS

/*
-- =============================================
-- Function:    dbo.usp_get_broadcast_result_listings
-- Author:      Matt Tantony
-- Create date: 2025-11-15
--
--
-- Description:
-- ============
--  Returns a list of all the results in a specified broadcast.
--
--  Listings are generated by:
--      - Filtering voting data from query parameters.
--      - Listing results.
--      - Sorting results by running order spot (descending).
--
--
-- Required input parameters:
-- ==========================
--  @contest_year INT
--      - Filters voting data by contest year.
--  @contest_stage NVARCHAR(10)
--      - Filters voting data by contest stage.
--      - Valid 'ContestStage' enum values: {'SemiFinal1', 'SemiFinal2', 'GrandFinal'}.
--
--
-- Returns:
-- ========
-- A list of 0, 1, or multiple listings rows with the following columns:
--  - running_order_spot INT
--      - The competitor's running order spot in the broadcast.
--  - country_code NCHAR(2)
--      - The competing country's ISO 3166-1 alpha-2 country code.
--  - country_name NVARCHAR(200)
--      - The competing country's short UK English name.
--  - act_name NVARCHAR(200)
--      - The competitor's act name.
--  - song_title NVARCHAR(200)
--      - The competitor's song title.
--  - jury_points INT
--      - The total jury points the competitor received, or NULL in a televote-only broadcast.
--      - Allows NULL.
--  - jury_rank INT
--      - The competitor's rank based on total jury points, or NULL in a televote-only broadcast.
--      - Allows NULL.
--  - televote_points INT
--      - The total televote points the competitor received.
--  - televote_rank INT
--      - The competitor's rank based on total televote points.
--  - overall_points INT
--      - The total overall points the competitor received.
--  - finishing_position INT
--      - The competitor's finishing position in the broadcast.
-- =============================================
*/


BEGIN

    SET NOCOUNT ON;

-- Filter voting data

    WITH filtered_voting_datum AS (SELECT k.contest_id,
                                          b.broadcast_id,
                                          bcta.competing_country_id,
                                          bcja.points_value AS jury_points_value,
                                          bcta.points_value AS televote_points_value
                                   FROM dbo.contest k
                                            JOIN dbo.broadcast b ON b.parent_contest_id = k.contest_id
                                            JOIN dbo.broadcast_competitor_televote_award bcta
                                                 ON bcta.broadcast_id = b.broadcast_id
                                            LEFT JOIN dbo.broadcast_competitor_jury_award bcja
                                                      ON bcja.broadcast_id = bcta.broadcast_id AND
                                                         bcja.competing_country_id = bcta.competing_country_id AND
                                                         bcja.voting_country_id = bcta.voting_country_id
                                   WHERE k.queryable = 1
                                     AND k.contest_year = @contest_year
                                     AND b.contest_stage = @contest_stage),

         aggregate_datum AS (SELECT fvd.contest_id,
                                    fvd.broadcast_id,
                                    fvd.competing_country_id,
                                    SUM(fvd.jury_points_value)     AS jury_points,
                                    SUM(fvd.televote_points_value) AS televote_points
                             FROM filtered_voting_datum fvd
                             GROUP BY fvd.contest_id, fvd.broadcast_id, fvd.competing_country_id)

-- Compile listings, sort, and return listings rows

    SELECT bc.running_order_spot,
           c.country_code,
           c.country_name,
           cp.act_name,
           cp.song_title,
           a.jury_points,
           IIF(a.jury_points IS NULL, NULL,
               RANK() OVER (PARTITION BY a.broadcast_id ORDER BY a.jury_points DESC)) AS jury_rank,
           a.televote_points,
           RANK() OVER (PARTITION BY a.broadcast_id ORDER BY a.televote_points DESC)  AS televote_rank,
           COALESCE(a.jury_points, 0) + a.televote_points                             AS overall_points,
           bc.finishing_position
    FROM aggregate_datum a
             JOIN dbo.broadcast_competitor bc
                  ON bc.broadcast_id = a.broadcast_id AND bc.competing_country_id = a.competing_country_id
             JOIN dbo.country c ON c.country_id = a.competing_country_id
             JOIN dbo.contest_participant cp
                  ON cp.contest_id = a.contest_id AND cp.participating_country_id = a.competing_country_id
    ORDER BY bc.running_order_spot;

END

GO
